scwin.f_Delete = async function(){
    let vConfirm = await $c.win.confirm("삭제하시겠습니까?");

    if(vConfirm){
        //ds_result_list.DeleteRow(ds_result_list.RowPosition);
        ds_result_list.deleteRow( ds_result_list.getRowPosition() );  
        ds_userPrivGroup.setCellData(1,"userId", ed_userId.getValue());
        //tr_save.Post();
        $c.sbm.execute(sbm_save);
        scwin.f_Retrieve();
        scwin.f_ContentsDisable();
        scwin.flag = 0;
    }else	{
        scwin.f_Cancel();
    }  
}

