scwin.f_Cancel = function() {
    scwin.flag = 0;
    //chb_useYn.checked = "false";
    let vPasswordExceptYn = passwordExceptYn.getValue();

    scwin.f_ContentsDisable();
    scwin.txt_checkUserDupl = "";

    ed_newPasswd.setMandatory(false);			
    //ed_newPasswd.validExp="";

    ed_newPasswdConfirm.setMandatory(false);			
    //ed_newPasswdConfirm.validExp="";

    //$c.gus.cfRefreshMandSign();

    if(scwin.vSysAdminYn=="1"){
        passwdExpyn.setDisabled(false);
    }else{
        passwdExpyn.setDisabled(true);
    }

    let vRowCount = scwin.txt_countRow;
    let vResultListPosition = ds_result_list.getRowPosition();


    // 20130327 변경
    let i;
    for( i=0 ; i < ds_result_list.getRowCount(); i++)		{
        //if(ds_result_list.getRowStatus(i) == 3 )	{
        if(ds_result_list.getRowStatus(i) == 'U' )	{
            //ds_result_list.Undo(i);
            ds_result_list.undoRow(i);
        }
        scwin.txt_newPasswdConfirm = "";
        ed_newPasswdConfirm.setValue("");
    }

    var chkCreate = false;
    for( i=0 ; i < ds_result_list.getRowCount(); i++)		{
        //if(ds_result_list.getRowStatus(i) == 1 )	{
        if(ds_result_list.getRowStatus(i) == 'C' )	{ //insert
            //ds_result_list.undoRow(i);
            ds_result_list.removeRow(i);
            chkCreate = true;
        }
        scwin.txt_newPasswdConfirm = "";
        ed_newPasswdConfirm.setValue("");
    }	
    //20130327 변경

    //ds_userPrivGroup.UndoAll();
    //ds_userPrivGroup.undoAll();
    scwin.fn_undo(ds_userPrivGroup);

    if(vRowCount=="" || vRowCount=="0"){
    // 조회를 하지 않은 경우
        scwin.f_Set("INIT");

    } else {
    // 조회를 한 경우
        scwin.f_Set("RETRIEVE");
        if(vResultListPosition > 0){
            if(vPasswordExceptYn){
                //cfDisableBtn([b_Create, b_Cancel, b_Save]);				
            }else{
                //cfDisableBtn([b_Cancel, b_Save, btnAddRow, btnDeleteRow, btnUndoRow]);
            }
        }else{
            if(vPasswordExceptYn){
                //cfDisableBtn([b_Create, b_Cancel, b_Save]);				
            }else{
                //cfDisableBtn([b_Cancel, b_Save, b_Update, b_Delete, btnAddRow, btnDeleteRow, btnUndoRow]);
            }
        }
    }


    if(chkCreate) { //신규 작업중이었으면 포커스 제일 끝으로
        var rowIndex = ds_result_list.getRowCount() - 1;
        ds_result_list.setRowPosition(rowIndex);
        gr_user.setFocusedCell(rowIndex, 0, false);
    }


    if( ds_result_list.getCellData(ds_result_list.getRowPosition(), "useYn") == 1)	{
        rd_useYn.setValue("1");
    } else {
        rd_useYn.setValue("0");
    }

}

