//-------------------------------------------------------------------------
scwin.f_PrivAddRow = function(){
    let vUserCountRow = ds_result_list.getRowCount();
    let vUserId = ds_result_list.getCellData(ds_result_list.getRowPosition(), "userId");

    if(vUserCountRow < 1){
        $c.win.alert("권한그룹을 추가할 사용자를 조회해 주십시오.");
        return false;
    }

    if(vUserId.trim()==""){
        $c.win.alert("권한그룹을 추가할 사용자ID를 입력해주십시오.");
        ed_privGrpId.setValue("");
        ed_userId.focus();
        return false;
    }	

    let row;
    //ds_userPrivGroup.AddRow();
    row = ds_userPrivGroup.insertRow();
    ds_userPrivGroup.setRowPosition(row);
    //행 삭제 시, 동작을 하지 않는 현상 수정
    gr_userPrivGroup.setFocusedCell(row, 0, false);

    ds_userPrivGroup.setCellData( ds_userPrivGroup.getRowPosition(), "userId", ds_result_list.getCellData(ds_result_list.getRowPosition(), "userId") );	

}

