     //행 삭제 시, 동작을 하지 않는 현상 수정
    let targetIdx = gr_userPrivGroup.getFocusedRowIndex();
    //let targetIdx = ds_userPrivGroup.getRowPosition();
    //let targetIdx = ds_userPrivGroup.getRowPosition();
    let m_totalIdx = ds_userPrivGroup.getTotalRow();
