                                ,"사원검색,사번,사원명"		// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                );

}


scwin.udc_clntNo_cb = async function(rtnList) {
    if ( rtnList != null) {
        if(rtnList[0] == "N/A") return false;
        ed_clntNo.setValue( rtnList[0] );	//사원코드
        ed_clntNm.setValue( rtnList[1] );	//사원명
        ed_clntNo.options.hidVal = ed_clntNo.getValue();

        $c.gus.cfSetReturnValue(rtnList, ed_clntNo, ed_clntNm);
    }

    //oGDS_temp.DataID = "/cm.bc.comnmgnt.usermgnt.cmd.RetrieveClntUserCMD.do?clntNo=" + txt_clntNo.value ;
    //oGDS_temp.reset();

    /**
     * 안되는 쿼리 AsIs는 오류 안 띄우지만 건수는(0) 우린 띄우니까 안돌린다.
     * 
    SELECT
	A.CLNT_NO ,
	A.CLNT_NM USER_NM ,
	A.ZIP ,
	A.ADDR_1 ,
	A.ADDR_2 ,
	A.EMP_NO -- 사원 거래처인 경우 사번이 NOT NULL ,
	A.ACCT_DEPT_CD ,
	B.ACCT_DEPT_NM
FROM
	TB_ZZ510 A ,
	TB_CO001 B
WHERE
