//-------------------------------------------------------------------------
//  권한그룹 체크
//-------------------------------------------------------------------------
scwin.f_CheckPrivGrpGridRegist = function() {
    let vPrivGroupId = ed_privGrpId.getValue();
    let vPrivGroupNm = ed_privGrpNm.getValue();

    if(vPrivGroupId.trim()!=""){
        let vPrivGrpCountRow = ds_userPrivGroup.getRowCount();
        let vDuplCount = 0;

        let vPrivGrpId;
        for(var i=0;i<vPrivGrpCountRow;i++){
            vPrivGrpId = ds_userPrivGroup.getCellData(i, "privGrpId");
            if(vPrivGroupId==vPrivGrpId){
                vDuplCount++;
            }
        }

        if(vDuplCount>0){
            $c.win.alert("이미 등록된 권한그룹입니다.");
            return false;
        }else{
            scwin.f_PrivAddRow();
            ds_userPrivGroup.setCellData(ds_userPrivGroup.getRowPosition(), "privGrpId", vPrivGroupId);
            ds_userPrivGroup.setCellData(ds_userPrivGroup.getRowPosition(), "privGrpNm", vPrivGroupNm);
        }
    }
}

