scwin.udc_temp_cb = function(rtnList) {
    if (rtnList != null ) {
        if(rtnList[0] == "N/A") return false;
        for(var i=0; i < ds_userPrivGroup.getRowCount(); i++){
            if(ds_userPrivGroup.getCellData(i, "privGrpId") == rtnList[0]){
                $c.win.alert("권한그룹 : "+ rtnList[0]+"은 이미 등록되어 있습니다.");
                return false;
                break;
            }
        }
        ds_userPrivGroup.setCellData(ds_userPrivGroup.getRowPosition(), "privGrpId", rtnList[0] );	//권한그룹ID
        ds_userPrivGroup.setCellData(ds_userPrivGroup.getRowPosition(), "privGrpNm", rtnList[1] );	//권한그룹명
    } 

}
