            , drawBorder: false       //cell의 border 지정(true, false)
            // ,useFooter:"true"        //다운로드시 Footer를 출력 할지 여부( "true"인경우 출력, "false"인경우 미출력)
        },

        {
              rowIndex: 2               //제목을 표시할 행 index
            , colIndex: 0               //제목을 표시할 열 index
            , rowSpan: 1                //병합할 행의 수
            , textAlign: "left"       //표시할 내용의 정렬 방법(left, center, right)
            , colSpan: calcaulatedColnum                //병합할 열의 수
            , text:  '조회일자 : '+$c.date.getServerDateTime("yyyyMMdd")         //표시할 내용(제목)
            , drawBorder: false       //cell의 border 지정(true, false)
            // ,useFooter:"true"        //다운로드시 Footer를 출력 할지 여부( "true"인경우 출력, "false"인경우 미출력)
        },
    ]; 
    console.log('scwin.f_userToExcel22');

    $c.data.downloadGridViewExcel(gridId, options, infoArr);
}


