scwin.gr_user_oncellclick = function (rowIndex, columnIndex, columnId) {

    let Row = rowIndex;
    //alert("lc_blockReason.BincColVal" + lc_blockReason.BincColVal);
	if(scwin.flag == 1)	{
		if(lc_blockReason.getValue() == "")	{
			$c.gus.cfEnableObjects([lc_blockReason, ed_blockCancelEtDt, ed_blockEtDt, ed_blockDt]);
