//	}	
	// 선택된 Row가 변경되었는지를 확인한다.
	if(scwin.row_confirm != Row)	{
		if(scwin.row_confirm == "")
			ds_result_list.setCellData(Row, "newPasswd", "");
		ds_result_list.setCellData(scwin.row_confirm, "newPasswd", "");
