        }

        //if(rd_useYn.getValue() == "1")	{
            //useYn_cond2.NameValue(1, "useYn") = 1;
        //}
        //else if(rd_useN.checked == true)	{
            //useYn_cond2.NameValue(1, "useYn") = 0;
        //}
        if(scwin.flag == 1)	{
            $c.gus.cfEnableObjects([lc_blockReason, ed_blockCancelEtDt, ed_blockEtDt, ed_blockDt]);
            //$c.gus.cfEnableObjects([calendar_blockCancelEtDt, calendar_blockEtDt, calendar_blockDt]);	
            if(rd_useYn.getValue() == "1")	{	
                $c.gus.cfDisableObjects([ed_blockDt]);
                //cfDisableObjects([calendar_blockDt]);			
            }
            if(rd_useYn.getValue() == "0")	{

                if(lc_blockReason.getValue() == "A" || lc_blockReason.getValue() == "B")	{
                    $c.gus.cfDisableObjects([ed_blockEtDt]);
                    //$c.gus.cfDisableObjects([calendar_blockEtDt]);				
                }else if(lc_blockReason.getValue() == "C" || lc_blockReason.getValue() == "D" || lc_blockReason.getValue() == "E")	{
                    $c.gus.cfDisableObjects([ed_blockCancelEtDt, ed_blockEtDt]);
                    //$c.gus.cfDisableObjects([calendar_blockCancelEtDt, calendar_blockEtDt]);		
                }else	{
                    $c.gus.cfDisableObjects([ed_blockEtDt]);
                    //cfDisableObjects([calendar_blockEtDt]);			
                }
            }
        }	

        let i;
        for( i=0 ; i < ds_result_list.getRowCount() ; i++)		{
            if(ds_result_list.getCellData(i, "userId") == ed_userId.getValue())	{
                //alert(rd_useY.checked);
                //alert(rd_useN.checked);
                /*
                if(	useYn_cond2.NameValue(1, "useYn") == 1)	{
                    oGDS_result_list.NameValue(i, "useYn") = 1;

                }
                else if(useYn_cond2.NameValue(1, "useYn") == 0)	{
                    oGDS_result_list.NameValue(i, "useYn") = 0;
                }
                */
                ds_result_list.setCellData(i, "useYn", (rd_useYn.getValue() == "1" ? "1" : "0") );
                break;
            }
        }        
}

