scwin.fn_undo = function (paramObj) {
    for( var idx = paramObj.getRowCount() -1; idx > -1 ;idx--){
        var rStat = paramObj.getRowStatus(idx);
        if(rStat == 'C') {
            //신규면 삭제
            paramObj.removeRow(idx);
        } else if(rStat == 'U') {
            paramObj.undoRow(idx);
        }
    }
};


//-------------------------------------------------------------------------
// 팝업 여부 검사
//-------------------------------------------------------------------------
scwin.f_IsPopUp = function(inObj, inObj2) {
    let inValue = inObj.getValue();
    if (!inObj.options) inObj.options = {};
    let hidValue = inObj.options.hidVal;

    if ($c.gus.cfIsNull(inValue)) {
        inObj.options.hidVal = "";
        inObj2.setValue("");

        return false;
    }
    if (inValue == hidValue) return false;

    return true;
};
